function whisper(s) {
  const parts = [];
  for (const c of s) {
    if (c >= "A" && c <= "Z") {
      parts.push(String.fromCharCode(c.charCodeAt(0) + 32));
    } else {
      parts.push(c);
    }
  }
  return parts.join("");
}

